---
import { Image } from "astro:assets"

import { cn } from "@/lib/utils"

const { class: className, src, alt = "", ...props } = Astro.props
---

{
  src && (
    <Image
      class={cn("h-full w-auto shrink-0 object-contain", className)}
      data-slot="logo-image"
      src={src as any}
      alt={alt}
      sizes="200px"
      widths={[200]}
      {...(props as any)}
    />
  )
}
